import React from 'react';
import { Line } from 'react-chartjs-2';
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  Title,
  Tooltip,
  Legend,
} from 'chart.js';

ChartJS.register(CategoryScale, LinearScale, PointElement, LineElement, Title, Tooltip, Legend);

const RevenueChart = ({ data }) => {
  // ❌ Было: data.revenue_chart
  // ✅ Стало: data?.revenue_chart
  if (!data || !data.revenue_chart) return <div>Нет данных</div>;

  const chartData = {
    labels: data.revenue_chart.map(d => d.date),
    datasets: [
      {
        label: 'Выручка',
        data: data.revenue_chart.map(d => d.value),
        fill: false,
        borderColor: 'rgb(75, 192, 192)',
        tension: 0.1,
      },
    ],
  };

  const options = {
    responsive: true,
    plugins: {
      legend: { display: false },
      title: { display: true, text: 'Динамика выручки' },
    },
  };

  return <Line data={chartData} options={options} />;
};

export default RevenueChart;
